import { workflow, node, trigger, expr } from '@n8n/workflow-sdk';

const manualTrigger = trigger({
  type: 'n8n-nodes-base.manualTrigger',
  version: 1,
  config: { name: 'When clicking "Execute Workflow"' },
});

const setNode = node({
  type: 'n8n-nodes-base.set',
  version: 3.4,
  config: {
    name: 'artifact click test',
    parameters: {
      mode: 'manual',
      fields: {
        values: [
          { name: 'message', type: 'stringValue', string: 'Hello from artifact click test' },
        ],
      },
    },
  },
});

export default workflow('id', 'artifact click test')
  .add(manualTrigger)
  .to(setNode);
